            function buildCard(ev) {
              var label = CAT_LABELS[ev.cat] || ev.cat;
              var img_src = IMGS[ev.cat] || '../assets/placeholder.png';
              
              return '<div class="india-ev-card" data-cat="' + ev.cat + '">'
                + '<a href="' + ev.link + '" target="_blank">'
                + '<div class="india-ev-card-banner">'
