              if (btn) btn.classList.add('active');

              // Show/hide cards
              var cards = document.querySelectorAll('.india-ev-card');
              var visible = 0;
              for (var j = 0; j < cards.length; j++) {
                if (cat === 'all' || cards[j].getAttribute('data-cat') === cat) {
                  cards[j].classList.remove('india-ev-hidden');
                  visible++;
                } else {
                  cards[j].classList.add('india-ev-hidden');
                }
              }

              var noResults = document.getElementById('noResults');
              if (visible === 0) noResults.classList.add('visible');
              else noResults.classList.remove('visible');
            }

            function initGrid() {
              var grid = document.getElementById('eventsGrid');
              var html = '';
              for (var i = 0; i < EV.length; i++) html += buildCard(EV[i]);
              grid.innerHTML = html;

              // Update count badges
              document.getElementById('cnt-all').textContent = EV.length;
              var cats = ['Hackathon','Coding Contest','Mentorship Program'];
              var ids  = ['Hackathon','CodingContest','MentorshipProgram'];
              for (var c = 0; c < cats.length; c++) {
                var n = EV.filter(function(e){ return e.cat === cats[c]; }).length;
                var el = document.getElementById('cnt-' + ids[c]);
                if (el) el.textContent = n;
              }
            }

            // Initialize
            document.addEventListener('DOMContentLoaded', initGrid);
            if(document.readyState === "complete" || document.readyState === "interactive") {
                initGrid();
            }
          </script>
        </section>
      </div>
